import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-05-11","description":"","frontmatter":{"title":"The Decoder — 2026-05-11","date":"2026-05-11T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-11-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-11-the-decoder.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-11-the-decoder.md"};function s(i,e,h,c,l,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🔓-the-decoder-—-2026-05-11" tabindex="-1">🔓 The Decoder — 2026-05-11 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-11" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-11&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="ai-agents-can-now-hack-computers-and-copy-themselves-and-they-re-getting-better-fast" tabindex="-1"><a href="https://the-decoder.com/ai-agents-can-now-hack-computers-and-copy-themselves-and-theyre-getting-better-fast/" target="_blank" rel="noreferrer">AI agents can now hack computers and copy themselves, and they&#39;re getting better fast</a> <a class="header-anchor" href="#ai-agents-can-now-hack-computers-and-copy-themselves-and-they-re-getting-better-fast" aria-label="Permalink to &quot;[AI agents can now hack computers and copy themselves, and they&#39;re getting better fast](https://the-decoder.com/ai-agents-can-now-hack-computers-and-copy-themselves-and-theyre-getting-better-fast/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-10</em></p><p>Palisade Research shows that AI agents can hack remote computers, copy themselves onto them, and form replication chains. In one year, the success rate jumped from 6 to 81 percent. The researchers expect remaining barriers to fall as models get better at hacking.</p><p>The article <a href="https://the-decoder.com/ai-agents-can-now-hack-computers-and-copy-themselves-and-theyre-getting-better-fast/" target="_blank" rel="noreferrer">AI agents can now hack computers and copy themselves, and they&#39;re getting better fast</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-and-openai-sit-down-with-religious-leaders-to-seek-ethical-advice" tabindex="-1"><a href="https://the-decoder.com/anthropic-and-openai-sit-down-with-religious-leaders-to-seek-ethical-advice/" target="_blank" rel="noreferrer">Anthropic and OpenAI sit down with religious leaders to seek ethical advice</a> <a class="header-anchor" href="#anthropic-and-openai-sit-down-with-religious-leaders-to-seek-ethical-advice" aria-label="Permalink to &quot;[Anthropic and OpenAI sit down with religious leaders to seek ethical advice](https://the-decoder.com/anthropic-and-openai-sit-down-with-religious-leaders-to-seek-ethical-advice/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-10</em></p><p>Anthropic and OpenAI are turning to religious leaders for help with AI ethics. At the first &quot;Faith-AI Covenant&quot; roundtable in New York, representatives from both companies met with faith leaders from various religions. Critics like AI researcher Rumman Chowdhury call the talks &quot;at best a distraction&quot; from concrete questions about regulation and control over AI systems.</p><p>The article <a href="https://the-decoder.com/anthropic-and-openai-sit-down-with-religious-leaders-to-seek-ethical-advice/" target="_blank" rel="noreferrer">Anthropic and OpenAI sit down with religious leaders to seek ethical advice</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="bytedance-plans-over-30-billion-for-ai-expansion-bets-big-on-chinese-chips" tabindex="-1"><a href="https://the-decoder.com/bytedance-plans-over-30-billion-for-ai-expansion-bets-big-on-chinese-chips/" target="_blank" rel="noreferrer">ByteDance plans over $30 billion for AI expansion, bets big on Chinese chips</a> <a class="header-anchor" href="#bytedance-plans-over-30-billion-for-ai-expansion-bets-big-on-chinese-chips" aria-label="Permalink to &quot;[ByteDance plans over $30 billion for AI expansion, bets big on Chinese chips](https://the-decoder.com/bytedance-plans-over-30-billion-for-ai-expansion-bets-big-on-chinese-chips/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-10</em></p><p>ByteDance is raising its planned AI spending for 2026 to over 200 billion yuan (roughly $30 billion), at least a 25 percent jump from earlier plans. The TikTok parent is increasingly turning to Chinese chips. Still, the figure looks modest next to the $725 billion that Google, Amazon, Microsoft, and Meta are planning to spend combined.</p><p>The article <a href="https://the-decoder.com/bytedance-plans-over-30-billion-for-ai-expansion-bets-big-on-chinese-chips/" target="_blank" rel="noreferrer">ByteDance plans over $30 billion for AI expansion, bets big on Chinese chips</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="metr-says-it-can-barely-measure-claude-mythos-palo-alto-networks-warns-of-autonomous-ai-attackers" tabindex="-1"><a href="https://the-decoder.com/metr-says-it-can-barely-measure-claude-mythos-palo-alto-networks-warns-of-autonomous-ai-attackers/" target="_blank" rel="noreferrer">METR says it can barely measure Claude Mythos, Palo Alto Networks warns of autonomous AI attackers</a> <a class="header-anchor" href="#metr-says-it-can-barely-measure-claude-mythos-palo-alto-networks-warns-of-autonomous-ai-attackers" aria-label="Permalink to &quot;[METR says it can barely measure Claude Mythos, Palo Alto Networks warns of autonomous AI attackers](https://the-decoder.com/metr-says-it-can-barely-measure-claude-mythos-palo-alto-networks-warns-of-autonomous-ai-attackers/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-10</em></p><p>METR can barely measure Claude Mythos Preview with its current test suite. Only five out of 228 tasks cover the relevant capability range. Meanwhile, Palo Alto Networks reports that frontier models autonomously chain vulnerabilities, shrinking the time from initial access to data exfiltration to just 25 minutes. Evaluation methods are growing more slowly than the models themselves, and that may be the bigger problem.</p><p>The article <a href="https://the-decoder.com/metr-says-it-can-barely-measure-claude-mythos-palo-alto-networks-warns-of-autonomous-ai-attackers/" target="_blank" rel="noreferrer">METR says it can barely measure Claude Mythos, Palo Alto Networks warns of autonomous AI attackers</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="gpt-5-5-costs-49-to-92-percent-more-than-its-predecessor-depending-on-the-input-length" tabindex="-1"><a href="https://the-decoder.com/gpt-5-5-costs-49-to-92-percent-more-than-its-predecessor-depending-on-the-input-length/" target="_blank" rel="noreferrer">GPT-5.5 costs 49 to 92 percent more than its predecessor, depending on the input length</a> <a class="header-anchor" href="#gpt-5-5-costs-49-to-92-percent-more-than-its-predecessor-depending-on-the-input-length" aria-label="Permalink to &quot;[GPT-5.5 costs 49 to 92 percent more than its predecessor, depending on the input length](https://the-decoder.com/gpt-5-5-costs-49-to-92-percent-more-than-its-predecessor-depending-on-the-input-length/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-10</em></p><p>OpenAI doubled GPT-5.5&#39;s list price compared to GPT-5.4, claiming shorter responses would offset the increase. An OpenRouter analysis of real usage data tells a different story: actual costs rose 49 to 92 percent depending on input length. Anthropic hiked Opus 4.7 prices too—and with both companies eyeing IPOs, the trend is unlikely to stop.</p><p>The article <a href="https://the-decoder.com/gpt-5-5-costs-49-to-92-percent-more-than-its-predecessor-depending-on-the-input-length/" target="_blank" rel="noreferrer">GPT-5.5 costs 49 to 92 percent more than its predecessor, depending on the input length</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
